section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/ai-over-reliance-self-audit.json",
  "title": "AI Over-Reliance Self-Audit",
  "type": "object",
  "required": [
    "artefact_id",
    "audit_period",
    "checklist_items",
    "score",
    "threshold",
    "remediation",
    "next_audit_date",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "audit_period": {
      "type": "string",
      "description": "ISO date range the audit covers",
      "minLength": 1
    },
    "checklist_items": {
      "type": "array",
      "description": "list of {id, prompt, passed, evidence} entries",
      "minItems": 1
    },
    "score": {
      "type": "number",
      "description": "passed/total ratio in [0,1]"
    },
    "threshold": {
      "type": "number",
      "description": "minimum acceptable score, conventionally 0.7"
    },
    "remediation": {
      "type": "array",
      "description": "list of drills/actions if score<threshold",
      "minItems": 1
    },
    "next_audit_date": {
      "type": "string",
      "description": "ISO date for the next cycle",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
